    with right:
        st.markdown('<div class="section-title">🔮 PREDICTION RESULT</div>', unsafe_allow_html=True)
        if predict_btn:
            X = np.array([[age, le_sex.transform([sex])[0], le_bp.transform([bp])[0], le_chol.transform([chol])[0], na_to_k]])
            pred_enc  = model.predict(X)[0]
            pred_drug = le_drug.inverse_transform([pred_enc])[0]
            proba     = model.predict_proba(X)[0]
            st.markdown(f'''
            <div class="pred-box">
              <div style="color:#8899bb;font-size:.85rem;letter-spacing:2px">Recommended Drug</div>
              <div class="pred-drug">{pred_drug}</div>
              <div class="pred-conf">Confidence: {max(proba)*100:.1f}%</div>
              <div style="margin-top:.5rem;color:#aaa;font-size:.9rem;">{DRUG_DESC.get(pred_drug,"")}</div>
            </div>''', unsafe_allow_html=True)
            st.markdown("<br>", unsafe_allow_html=True)
            st.markdown('<div class="section-title">📊 CLASS PROBABILITIES</div>', unsafe_allow_html=True)
            fig = go.Figure()
            for cls,prob in zip(le_drug.classes_, proba):
                color = DRUG_COLORS.get(cls,"#888")
                fig.add_trace(go.Bar(x=[prob*100],y=[cls],orientation="h",marker=dict(color=color),text=[f"{prob*100:.1f}%"],textposition="outside",textfont=dict(color=color,size=13,family="Orbitron"),name=cls))
